const questions = require('./daily_quiz_slack.json').questions;
const randomQ = questions[Math.floor(Math.random() * questions.length)];
const letters = ['A','B','C','D'];
const optText = randomQ.options.map((o,i) => `${letters[i]}. ${o}`).join('\n');

const payload = {
  channel: '#daily-quiz',
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `🧠 Daily Quiz — ${randomQ.topic_label} (${randomQ.level_label})` } },
    { type: 'section', text: { type: 'mrkdwn', text: `*${randomQ.question}*` } },
    { type: 'section', text: { type: 'mrkdwn', text: optText } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: 'React với 🇦 🇧 🇨 🇩 · Đáp án reveal sau 4h ⏳' }] }
  ]
};
